51	/// Resolve the workspace root and backend, or exit with a helpful error.
52	///
53	/// Supports two modes:
54	/// - **Workspace mode**: CWD is inside the cuda-oxide repo (detected by
55	///   `crates/rustc-codegen-cuda` directory). Examples are resolved from the
56	///   workspace examples directory.
57	/// - **Standalone mode**: CWD has a `Cargo.toml` but is not inside the
58	///   workspace. The backend is located via cache or auto-fetch. Commands
59	///   like `run` operate on the current directory directly.
60	pub fn resolve_context() -> Context {
61	    if let Some(workspace_root) = backend::find_workspace_root() {
62	        let codegen_crate = workspace_root.join("crates/rustc-codegen-cuda");
63	        let examples_dir = codegen_crate.join("examples");
64	        let config = load_oxide_config(&workspace_root);
65	        let backend_so = backend::find_or_build_backend(&workspace_root, config.backend.as_deref());
66	        return Context {
67	            workspace_root,
68	            codegen_crate,
69	            examples_dir,
70	            backend_so,
71	            is_workspace: true,
72	            config,
73	        };
74	    }
75	
76	    let cwd = std::env::current_dir().unwrap_or_else(|e| {
77	        eprintln!("Error: cannot determine current directory: {}", e);
78	        std::process::exit(1);
79	    });
80	
81	    if cwd.join("Cargo.toml").is_file() {
82	        let config = load_oxide_config(&cwd);
83	        let backend_so = backend::find_or_build_backend(&cwd, config.backend.as_deref());
84	        return Context {
85	            workspace_root: cwd.clone(),
86	            codegen_crate: cwd.clone(),
87	            examples_dir: cwd.clone(),
88	            backend_so,
89	            is_workspace: false,
90	            config,
91	        };
92	    }
93	
94	    eprintln!("Error: Could not find cuda-oxide workspace or a standalone Cargo.toml.");
95	    eprintln!();
96	    eprintln!("Run from inside the cuda-oxide repository, or from a project created");
97	    eprintln!("with `cargo oxide new <name>`.");
98	    std::process::exit(1);
99	}
